def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        ratio = item / capacity
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 2:
            exponent = 4
            base_penalty = (ratio ** exponent) / 2
            for k in range(2, 6):
                base_penalty += (ratio ** (exponent * k)) / (k * 3)
            priorities[i] = base_penalty * (1 + np.sin(ratio))
        elif 1 < ratio <= 2:
            weighted_sum = 0
            for x in range(1, 6):
                sign = (-1) ** x
                weighted_sum += sign * (ratio ** (2 * x)) / (x + 1)
            priorities[i] = weighted_sum * 8 + np.log1p(ratio)
        elif 0 < ratio <= 1:
            score = 0
            for j in range(1, 8):
                sign = -1 if j % 3 == 0 else 1
                term = sign * (ratio ** j) / (j ** 1.5)
                score += term
            if ratio < 0.2:
                priorities[i] = abs(score) * 20
            elif ratio < 0.5:
                priorities[i] = abs(score) * 12 + 2 * ratio
            else:
                priorities[i] = abs(score) * 7 + np.exp(-ratio)
            if 0.75 < ratio < 1:
                extra = 0
                for m in range(1, 5):
                    extra += ((-1) ** m) * (ratio ** m) / (m + 2)
                priorities[i] += extra * 3
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
    return priorities
